import './App.css';
//import EWGlobalStyles from './EWGlobalStyles';
//import EWPuffs from './EWPuffs';
//import EWButton from './EWButton';
import UAT from './UAT';
import { createRoot } from 'react-dom/client';
import React, { ReactElement, useState, useEffect } from 'react';
import { Animator } from '@arwes/react-animator';
import { Puffs } from '@arwes/react-bgs';

const Sandbox = (): ReactElement => {
  const [active, setActive] = useState(true);

  useEffect(() => {
    const iid = setInterval(() => setActive((active) => !active), 3_000);
    return () => clearInterval(iid);
  }, []);

  return (
    <Animator
      active={active}
      duration={{
        // The duration of an individual animation sequence.
        interval: 2
      }}
    >
      <div style={{
        position: 'relative',
        width: '80vw',
        height: '80vh'
      }}>
        <Puffs
          color='hsla(180, 100%, 75%, 0.5)'
          quantity={20}
        />
      </div>
    </Animator>
  );
}

createRoot(document.querySelector('#root')).render(<Sandbox />);

export default Sandbox;
